'use strict';

var $TypeError = require('es-errors/type');
var isObject = require('es-object-atoms/isObject');

var Call = require('./Call');
var CreateDataProperty = require('./CreateDataProperty');
var EnumerableOwnPropertyNames = require('./EnumerableOwnPropertyNames');
var Get = require('./Get');
var IsArray = require('./IsArray');
var LengthOfArrayLike = require('./LengthOfArrayLike');
var ToString = require('./ToString');

var forEach = require('../helpers/forEach');



module.exports = function InternalizeJSONProperty(holder, name, reviver) {
	if (!isObject(holder)) {
		throw new $TypeError('Assertion failed: `holder` is not an Object');
	}
	if (typeof name !== 'string') {
		throw new $TypeError('Assertion failed: `name` is not a String');
	}
	if (typeof reviver !== 'function') {
		throw new $TypeError('Assertion failed: `reviver` is not a Function');
	}

	var val = Get(holder, name); 

	if (isObject(val)) { 
		var isArray = IsArray(val); 
		if (isArray) { 
			var I = 0; 

			var len = LengthOfArrayLike(val, 'length'); 

			while (I < len) { 
				var newElement = InternalizeJSONProperty(val, ToString(I), reviver); 

				if (typeof newElement === 'undefined') { 
					delete val[ToString(I)]; 
				} else { 
					CreateDataProperty(val, ToString(I), newElement); 
				}

				I += 1; 
			}
		} else { 
			var keys = EnumerableOwnPropertyNames(val, 'key'); 

			forEach(keys, function (P) { 
				
				var newElement = InternalizeJSONProperty(val, P, reviver); 

				if (typeof newElement === 'undefined') { 
					delete val[P]; 
				} else { 
					CreateDataProperty(val, P, newElement); 
				}
			});
		}
	}

	return Call(reviver, holder, [name, val]); 
};
